"use strict";parserFactory.register("gravitynovels.com",()=>new GravityNovelsParser);class GravityNovelsParser extends Parser{constructor(){super()}async getChapterUrls(e){return[...e.querySelectorAll("section#chapters a")].map(e=>util.hyperLinkToChapter(e))}findContent(e){return e.querySelector(".entry-content")||e.querySelector("#chapter-content")}extractTitleImpl(e){return e.querySelector("h1.story__identity-title")}extractAuthor(e){let t=e.querySelector(".author");return t?.textContent??super.extractAuthor(e)}findChapterTitle(e){return e.querySelector("h1.chapter__title")}findCoverImageUrl(e){return util.getFirstImgSrc(e,"figure.story__thumbnail")}getInformationEpubItemChildNodes(e){return[...e.querySelectorAll("section.story__summary")]}}